    //   maskProps: { style: { backgroundColor: 'red' } }
    // }
    let toast = Toast.show({
      style: { backgroundColor: 'blue', color: 'green' },
      maskProps: { style: { backgroundColor: 'red' } },
      position: 'middle',
      content: 'show toast',
      duration: 2000,
      maskClickable: false,
      onVisibleChange: (visible) => {
        console.log('custom visible:', visible)
      }
    })
    console.log(toast)

